function whitelistAddress() external {
    require(totalWhitelist < maxWhitelist, "SS_Whitelist: Reached whitelist limit");
    require(userSettings[msg.sender] == false, "SS_Whitelist: User is whitelisted");

    userSettings[msg.sender] = true;
    totalWhitelist++;
    emit WhitelistedAddress(totalWhitelist, msg.sender);
}

function setMaxWhitelist(uint256 _maxWhitelist) external {
    require(msg.sender == lotOwner, "SS_Whitelist: not lot owner");
    require(_maxWhitelist > maxWhitelist, "SS_Whitelist: amount cannot be lesser that the current whitelist amount");
    require(_maxWhitelist > totalWhitelist, "SS_Whitelist: amount cannot be lesser that the current whitelist amount");
    maxWhitelist = _maxWhitelist;
    emit ChangeMaxWhitelist(totalWhitelist, maxWhitelist);
}
